#include <stdio.h>
int main() {
    int T, N, i, j, seconds, swapped;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int arr[N];
        for (i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        seconds = 0;
        do {
            swapped = 0;
            for (i = 0; i < N - 1; i++) {
                if (arr[i] == 0 && arr[i + 1] == 1) {
                    int temp = arr[i];
                    arr[i] = arr[i + 1];
                    arr[i + 1] = temp;
                    swapped = 1;
                }
            }
            if (swapped) seconds++;
        } while (swapped);
        printf("%d\n", seconds);
    }
    return 0;
}

