import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int seconds = 0;
            boolean swapped;
            do {
                swapped = false;
                for (int i = 0; i < N - 1; i++) {
                    if (arr[i] == 0 && arr[i + 1] == 1) {
                        int temp = arr[i];
                        arr[i] = arr[i + 1];
                        arr[i + 1] = temp;
                        swapped = true;
                    }
                }
                if (swapped) seconds++;
            } while (swapped);
            System.out.println(seconds);
        }
    }
}

