    let seconds = 0;
    let swapped = true;
    while (swapped) {
        swapped = false;
        for (let j = 0; j < N - 1; j++) {
            if (arr[j] === 0 && arr[j + 1] === 1) {
                [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                swapped = true;
            }
        }
        if (swapped) seconds++;
    }
    console.log(seconds);
}
